#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,m; scanf("%d %d",&n,&m);
        int *stack = (int*)malloc(n*sizeof(int));
        int top = 0; // current size
        char op[10];
        for(int i=0;i<m;i++){
            scanf("%s",op);
            if(strcmp(op,"push")==0){
                int x; scanf("%d",&x);
                if(top < n) stack[top++] = x; // ignore if full
            }else if(strcmp(op,"pop")==0){
                if(top==0) printf("-1\n");
                else printf("%d\n",stack[--top]);
            }else if(strcmp(op,"peek")==0){
                if(top==0) printf("-1\n");
                else printf("%d\n",stack[top-1]);
            }else if(strcmp(op,"isEmpty")==0){
                printf(top==0?"True\n":"False\n");
            }else if(strcmp(op,"isFull")==0){
                printf(top==n?"True\n":"False\n");
            }
        }
        free(stack);
    }
    return 0;
}

