import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int n = Integer.parseInt(br.readLine().trim());
            int m = Integer.parseInt(br.readLine().trim());
            int[] stack = new int[n];
            int top = 0; // current size
            for (int i = 0; i < m; i++) {
                String line = br.readLine();
                String[] parts = line.split(" ");
                String op = parts[0];
                switch (op) {
                    case "push":
                        int x = Integer.parseInt(parts[1]);
                        if (top < n) stack[top++] = x;
                        break;
                    case "pop":
                        if (top == 0) out.append("-1\n");
                        else out.append(stack[--top]).append('\n');
                        break;
                    case "peek":
                        if (top == 0) out.append("-1\n");
                        else out.append(stack[top - 1]).append('\n');
                        break;
                    case "isEmpty":
                        out.append(top == 0 ? "True" : "False").append('\n');
                        break;
                    case "isFull":
                        out.append(top == n ? "True" : "False").append('\n');
                        break;
                }
            }
        }
        System.out.print(out.toString());
    }
}

