import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx]); idx += 1
    out = []
    for _ in range(T):
        n = int(data[idx]); idx += 1
        m = int(data[idx]); idx += 1
        stack = []
        for __ in range(m):
            parts = data[idx].split(); idx += 1
            op = parts[0]
            if op == 'push':
                x = int(parts[1])
                if len(stack) < n:
                    stack.append(x)
            elif op == 'pop':
                if stack:
                    out.append(str(stack.pop()))
                else:
                    out.append('-1')
            elif op == 'peek':
                if stack:
                    out.append(str(stack[-1]))
                else:
                    out.append('-1')
            elif op == 'isEmpty':
                out.append('True' if not stack else 'False')
            elif op == 'isFull':
                out.append('True' if len(stack) == n else 'False')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

